// ======================================================
function numeroSeguro(valor) {
  if (valor === null || valor === undefined || valor === "") return 0;

  const n = Number(
    String(valor)
      .replace(",", ".")
      .replace(/[^\d.-]/g, "")
  );

  return Number.isFinite(n) ? n : 0;
}

