// SEPARA WORKLAB E APOIO
// ======================================================
const worklab = itens.filter(item => item.origem === "worklab");
const apoio = itens.filter(item => item.origem === "apoio");

// ======================================================
// MONTA MAPA DO APOIO POR PACIENTE NORMALIZADO
// ======================================================
const mapaApoio = new Map();

for (const item of apoio) {
  const paciente = String(item.Paciente || "").trim();
  if (!paciente) continue;

  const chave = normalizarTexto(paciente);
  mapaApoio.set(chave, item);
}

const resultado = [];

// ======================================================
// COMPARA SOMENTE PACIENTES EXISTENTES NOS DOIS LADOS
// ======================================================
for (const itemWorklab of worklab) {
  const pacienteWorklab = String(itemWorklab.Paciente || "").trim();
  if (!pacienteWorklab) continue;

  const chavePaciente = normalizarTexto(pacienteWorklab);

  const itemApoio = mapaApoio.get(chavePaciente);

  if (!itemApoio) continue;

  const quantidadeExamesWorklab = numeroSeguro(itemWorklab.quantidadeExames);
  const quantidadeExamesApoio = numeroSeguro(itemApoio.quantidadeExames);

  const matchQuantidadeExames =
    quantidadeExamesWorklab === quantidadeExamesApoio;

  if (matchQuantidadeExames) continue;

  resultado.push({
    json: {
      Paciente: pacienteWorklab,
      pacienteNormalizado: chavePaciente,

      PacienteWorklab: pacienteWorklab,
      PacienteApoio: itemApoio.Paciente || "",

      existeNoWorklab: true,
      existeNoApoio: true,

      quantidadeExamesWorklab,
      quantidadeExamesApoio,
      diferencaQuantidade: quantidadeExamesWorklab - quantidadeExamesApoio,

      matchPaciente: true,
      matchQuantidadeExames: false,

      erro: true,
      tipoDivergencia: "QUANTIDADE_EXAMES_DIFERENTE",
      mensagem: "Paciente encontrado, mas a quantidade de exames está diferente",

      dadosWorklab: itemWorklab,
      dadosApoio: itemApoio
    }
  });
}

return resultado;

// ======================================================
// PACIENTES QUE ESTÃO NO APOIO
// E NÃO FORAM ENCONTRADOS NO WORKLAB
//
// AJUSTE:
// quantidadeExamesApoio = quantidade de itens em itemApoio.amostras
// ======================================================

const itens = $input.all().map(item => item.json);

// ======================================================
// NORMALIZA TEXTO
// ======================================================
function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

// ======================================================
// CONVERTE QUANTIDADE COM SEGURANÇA
// ======================================================
function numeroSeguro(valor) {
  if (valor === null || valor === undefined || valor === "") return 0;

  const n = Number(
    String(valor)
      .replace(",", ".")
      .replace(/[^\d.-]/g, "")
  );

  return Number.isFinite(n) ? n : 0;
}

// ======================================================
// GARANTE ARRAY
// ======================================================
function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) return valor;

  if (typeof valor === "object") return [valor];

  return [];
}

// ======================================================
// QUANTIDADE CORRETA DO APOIO
// Conta quantos itens existem em amostras
// ======================================================
function quantidadeApoioPorAmostras(itemApoio) {
  const amostras = garantirArray(itemApoio?.amostras);
  return amostras.length;
}

// ======================================================
// SEPARA WORKLAB E APOIO
// ======================================================
const worklab = itens.filter(item => item.origem === "worklab");
const apoio = itens.filter(item => item.origem === "apoio");

// ======================================================
// MONTA SET DOS PACIENTES DO WORKLAB
// ======================================================
const pacientesWorklab = new Set();

for (const item of worklab) {
  const paciente = String(item.Paciente || "").trim();
  if (!paciente) continue;

  const chavePaciente = normalizarTexto(paciente);
  pacientesWorklab.add(chavePaciente);
}

// ======================================================
// PROCURA PACIENTES DO APOIO QUE NÃO EXISTEM NO WORKLAB
// ======================================================
const resultado = [];

for (const itemApoio of apoio) {
  const pacienteApoio = String(itemApoio.Paciente || "").trim();
  if (!pacienteApoio) continue;

  const chavePaciente = normalizarTexto(pacienteApoio);

  const existeNoWorklab = pacientesWorklab.has(chavePaciente);

  if (existeNoWorklab) continue;

  // ======================================================
  // AQUI ESTÁ O AJUSTE:
  // quantidade do apoio vem de amostras.length
  // ======================================================
  const quantidadeExamesApoio = quantidadeApoioPorAmostras(itemApoio);

  const quantidadeOriginalApoio = numeroSeguro(
    itemApoio.quantidadeExames
  );

  resultado.push({
    json: {
      Paciente: pacienteApoio,
      pacienteNormalizado: chavePaciente,

      PacienteWorklab: "",
      PacienteApoio: pacienteApoio,

      existeNoWorklab: false,
      existeNoApoio: true,

      quantidadeExamesWorklab: 0,

      // Quantidade correta: quantidade de amostras
      quantidadeExamesApoio,

      // Campos auxiliares para conferência
      quantidadeOriginalApoio,
      quantidadeAmostrasApoio: quantidadeExamesApoio,

      diferencaQuantidade: 0 - quantidadeExamesApoio,

      matchPaciente: false,
      matchQuantidadeExames: false,

      erro: true,
      tipoDivergencia: "PACIENTE_EXTRA_NO_APOIO",
      mensagem: "Paciente existe no apoio, mas não existe no worklab",

      dadosWorklab: null,
      dadosApoio: itemApoio
    }
  });
}

return resultado;

// ======================================================
// EXPLODE dadosApoio.detalhesExames
// Retorna 1 item para cada detalheExame do apoio
// Funciona se detalhesExames vier como ARRAY ou OBJETO
// ======================================================

