  const detalhes = garantirArray(
    dadosApoioOriginal.detalhesExames
  );

  // ======================================================
  // SE NÃO TIVER detalhesExames, RETORNA O ITEM NORMAL
  // ======================================================
  if (detalhes.length === 0) {
