        pedidoAlfanumericoApoio: detalhe.pedidoAlfanumerico || "",
        quantidadeExamesNaLinhaApoio: detalhe.quantidadeExamesNaLinha ?? 0,
        ultimoEventoBagApoio: detalhe.ultimoEventoBag || "",
        rowNumberOriginalApoio: detalhe.row_number_original || "",

        // ==============================
        // WORKLAB MANTÉM COMO VEIO
        // ==============================
        dadosWorklab: item.dadosWorklab || null,

        // ==============================
        // APOIO COM APENAS 1 DETALHE
        // ==============================
        dadosApoio: {
