            amostra: detalhe.amostra || "",
            lote: detalhe.lote || "",
            conservacao: detalhe.conservacao || "",
            pedido: detalhe.pedido || "",
            pedidoAlfanumerico: detalhe.pedidoAlfanumerico || "",
            quantidadeExamesNaLinha: detalhe.quantidadeExamesNaLinha ?? 0,
            ultimoEventoBag: detalhe.ultimoEventoBag || "",
            row_number_original: detalhe.row_number_original || ""
          }
        }
      }
    });
  });
}

return resultado;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// ======================================================
// EXPLODE APENAS dadosWorklab.registros
// E RETORNA APENAS ITENS COM A MENSAGEM:
// "Paciente do worklab não encontrado no apoio"
// ======================================================

const itens = $input.all().map(item => item.json);

const resultado = [];

const MENSAGEM_FILTRO = "Paciente do worklab não encontrado no apoio";

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) return valor;

  if (typeof valor === "object") return [valor];

  return [];
}

for (const item of itens) {
  const mensagemItem = String(item.mensagem || "").trim();

  // ======================================================
  // FILTRA ANTES DE EXPLODIR
  // Se a mensagem não for a desejada, ignora o item inteiro
  // ======================================================
  if (mensagemItem !== MENSAGEM_FILTRO) {
    continue;
  }

  const dadosWorklabOriginal = item.dadosWorklab || null;

  const registros = garantirArray(
    dadosWorklabOriginal?.registros
  );

  // ======================================================
  // SE NÃO TIVER REGISTROS, RETORNA O ITEM COMO ESTÁ
  // DESDE QUE A MENSAGEM SEJA A DESEJADA
  // ======================================================
  if (registros.length === 0) {
    resultado.push({
      json: {
        ...item,
        indiceRegistroWorklab: 0,
        totalRegistrosWorklab: 0,
        dadosApoio: null
      }
    });

    continue;
  }

  // ======================================================
  // EXPLODE 1 ITEM PARA CADA REGISTRO DO WORKLAB
  // ======================================================
  registros.forEach((registro, index) => {
    resultado.push({
      json: {
        Paciente: item.Paciente || "",
        pacienteNormalizado: item.pacienteNormalizado || "",

        PacienteWorklab: item.PacienteWorklab || "",
        PacienteApoio: item.PacienteApoio || "",

        existeNoWorklab: item.existeNoWorklab ?? true,
        existeNoApoio: item.existeNoApoio ?? false,

        quantidadeExamesWorklab: item.quantidadeExamesWorklab ?? 0,
        quantidadeExamesApoio: item.quantidadeExamesApoio ?? 0,
        diferencaQuantidade: item.diferencaQuantidade ?? 0,

        matchPaciente: item.matchPaciente ?? false,
        matchQuantidadeExames: item.matchQuantidadeExames ?? false,

        erro: item.erro ?? true,
        tipoDivergencia: item.tipoDivergencia || "PACIENTE_NAO_ENCONTRADO_NO_APOIO",
        mensagem: item.mensagem || MENSAGEM_FILTRO,

        indiceRegistroWorklab: index + 1,
        totalRegistrosWorklab: registros.length,

        exameWorklab: registro.Exame || "",
        descricaoExameWorklab: registro["Descrição Exame"] || "",
        rowNumberOriginalWorklab: registro.row_number_original || "",

        dadosWorklab: {
          nomeRelatorio: dadosWorklabOriginal?.nomeRelatorio || "",
          dataRelatorio: dadosWorklabOriginal?.dataRelatorio || "",
          dataCadastro: dadosWorklabOriginal?.dataCadastro || "",
          Paciente: dadosWorklabOriginal?.Paciente || "",
          pacienteNormalizado: dadosWorklabOriginal?.pacienteNormalizado || "",
          quantidadeExames: dadosWorklabOriginal?.quantidadeExames ?? 0,

          exames: registro.Exame ? [registro.Exame] : [],
          examesTexto: registro.Exame || "",

          linhasOriginais: registro.row_number_original
            ? [registro.row_number_original]
            : [],

          registros: [
            {
              ...registro
            }
          ],

          origem: dadosWorklabOriginal?.origem || "worklab"
        },

        dadosApoio: null
      }
    });
  });
}

return resultado;

// ======================================================
// EXPLODE WORKLAB + APOIO COM COMBINAÇÃO
//
// Se Worklab tiver 1 registro e Apoio tiver 2 detalhes:
// saída = 2 itens
// item 1: Worklab[0] + Apoio[0]
// item 2: Worklab[0] + Apoio[1]
//
// Se Worklab tiver 4 registros e Apoio tiver 1 detalhe:
// saída = 4 itens
// item 1: Worklab[0] + Apoio[0]
// item 2: Worklab[1] + Apoio[0]
// item 3: Worklab[2] + Apoio[0]
// item 4: Worklab[3] + Apoio[0]
// ======================================================

const itens = $input.all().map(item => item.json);

const resultado = [];

function garantirArray(valor) {
  if (!valor) return [];
  if (Array.isArray(valor)) return valor;
  if (typeof valor === "object") return [valor];
  return [];
}

function montarBase(item) {
  return {
    Paciente: item.Paciente || "",
    pacienteNormalizado: item.pacienteNormalizado || "",

    PacienteWorklab: item.PacienteWorklab || "",
    PacienteApoio: item.PacienteApoio || "",

    existeNoWorklab: item.existeNoWorklab ?? false,
    existeNoApoio: item.existeNoApoio ?? false,

    quantidadeExamesWorklab: item.quantidadeExamesWorklab ?? 0,
    quantidadeExamesApoio: item.quantidadeExamesApoio ?? 0,
    diferencaQuantidade: item.diferencaQuantidade ?? 0,

    matchPaciente: item.matchPaciente ?? false,
    matchQuantidadeExames: item.matchQuantidadeExames ?? false,

    erro: item.erro ?? false,
    tipoDivergencia: item.tipoDivergencia || "",
    mensagem: item.mensagem || ""
  };
}

function montarDadosWorklab(dadosWorklabOriginal, registro) {
  if (!registro) return null;

  return {
    nomeRelatorio: dadosWorklabOriginal?.nomeRelatorio || "",
    dataRelatorio: dadosWorklabOriginal?.dataRelatorio || "",
    dataCadastro: dadosWorklabOriginal?.dataCadastro || "",
    Paciente: dadosWorklabOriginal?.Paciente || "",
    pacienteNormalizado: dadosWorklabOriginal?.pacienteNormalizado || "",
    quantidadeExames: dadosWorklabOriginal?.quantidadeExames ?? 0,

    exames: registro.Exame ? [registro.Exame] : [],
    examesTexto: registro.Exame || "",

    linhasOriginais: registro.row_number_original
      ? [registro.row_number_original]
      : [],

    registros: [
      {
        ...registro
      }
    ],

    origem: dadosWorklabOriginal?.origem || "worklab"
  };
}

function montarDadosApoio(dadosApoioOriginal, detalhe) {
  if (!detalhe) return null;

  return {
    nomeRelatorio: dadosApoioOriginal?.nomeRelatorio || "",
    dataRelatorio: dadosApoioOriginal?.dataRelatorio || "",
    Paciente: dadosApoioOriginal?.Paciente || "",
    pacienteNormalizado: dadosApoioOriginal?.pacienteNormalizado || "",
    quantidadeExames: dadosApoioOriginal?.quantidadeExames ?? 0,

    exames: detalhe.quantidadeExamesNaLinha !== undefined
      ? [String(detalhe.quantidadeExamesNaLinha)]
      : [],

    examesTexto: detalhe.quantidadeExamesNaLinha !== undefined
      ? String(detalhe.quantidadeExamesNaLinha)
      : "",

    amostras: detalhe.amostra ? [detalhe.amostra] : [],
    pedidos: detalhe.pedido ? [detalhe.pedido] : [],
    lotes: detalhe.lote ? [detalhe.lote] : [],
    eventosBag: detalhe.ultimoEventoBag ? [detalhe.ultimoEventoBag] : [],

    linhasOriginais: detalhe.row_number_original
      ? [detalhe.row_number_original]
      : [],

    detalhesExames: [
      {
        ...detalhe
      }
    ],

    origem: dadosApoioOriginal?.origem || "apoio"
  };
}

for (const item of itens) {
  const dadosWorklabOriginal = item.dadosWorklab || null;
  const dadosApoioOriginal = item.dadosApoio || null;

  const registrosWorklab = garantirArray(
    dadosWorklabOriginal?.registros ||
    dadosWorklabOriginal?.registro
  );

  const detalhesApoio = garantirArray(
    dadosApoioOriginal?.detalhesExames ||
    dadosApoioOriginal?.detalheExame
  );

  // ======================================================
  // CASO 1: TEM WORKLAB E TEM APOIO
  // Faz combinação de todos os registros Worklab
  // com todos os detalhes Apoio.
  // ======================================================
  if (registrosWorklab.length > 0 && detalhesApoio.length > 0) {
    registrosWorklab.forEach((registro, indexWorklab) => {
      detalhesApoio.forEach((detalhe, indexApoio) => {
        resultado.push({
          json: {
            ...montarBase(item),

            origemExplodida: "worklab_apoio",

            indiceRegistroWorklab: indexWorklab + 1,
            totalRegistrosWorklab: registrosWorklab.length,

            indiceDetalheApoio: indexApoio + 1,
            totalDetalhesApoio: detalhesApoio.length,

            exameWorklab: registro.Exame || "",
            descricaoExameWorklab: registro["Descrição Exame"] || "",
            rowNumberOriginalWorklab: registro.row_number_original || "",

            amostraApoio: detalhe.amostra || "",
            loteApoio: detalhe.lote || "",
            conservacaoApoio: detalhe.conservacao || "",
            pedidoApoio: detalhe.pedido || "",
            pedidoAlfanumericoApoio: detalhe.pedidoAlfanumerico || "",
            quantidadeExamesNaLinhaApoio: detalhe.quantidadeExamesNaLinha ?? "",
            ultimoEventoBagApoio: detalhe.ultimoEventoBag || "",
            rowNumberOriginalApoio: detalhe.row_number_original || "",

            dadosWorklab: montarDadosWorklab(
              dadosWorklabOriginal,
              registro
            ),

            dadosApoio: montarDadosApoio(
              dadosApoioOriginal,
              detalhe
            )
          }
        });
      });
    });

    continue;
  }

  // ======================================================
  // CASO 2: TEM SÓ WORKLAB
  // ======================================================
  if (registrosWorklab.length > 0 && detalhesApoio.length === 0) {
    registrosWorklab.forEach((registro, indexWorklab) => {
      resultado.push({
        json: {
          ...montarBase(item),

          origemExplodida: "worklab",

          indiceRegistroWorklab: indexWorklab + 1,
          totalRegistrosWorklab: registrosWorklab.length,

          indiceDetalheApoio: 0,
          totalDetalhesApoio: 0,

          exameWorklab: registro.Exame || "",
          descricaoExameWorklab: registro["Descrição Exame"] || "",
          rowNumberOriginalWorklab: registro.row_number_original || "",

          amostraApoio: "",
          loteApoio: "",
          conservacaoApoio: "",
          pedidoApoio: "",
          pedidoAlfanumericoApoio: "",
          quantidadeExamesNaLinhaApoio: "",
          ultimoEventoBagApoio: "",
          rowNumberOriginalApoio: "",

          dadosWorklab: montarDadosWorklab(
            dadosWorklabOriginal,
            registro
          ),

          dadosApoio: null
        }
      });
    });

    continue;
  }

  // ======================================================
  // CASO 3: TEM SÓ APOIO
  // ======================================================
  if (registrosWorklab.length === 0 && detalhesApoio.length > 0) {
    detalhesApoio.forEach((detalhe, indexApoio) => {
      resultado.push({
        json: {
          ...montarBase(item),

          origemExplodida: "apoio",

          indiceRegistroWorklab: 0,
          totalRegistrosWorklab: 0,

          indiceDetalheApoio: indexApoio + 1,
          totalDetalhesApoio: detalhesApoio.length,

          exameWorklab: "",
          descricaoExameWorklab: "",
          rowNumberOriginalWorklab: "",

          amostraApoio: detalhe.amostra || "",
          loteApoio: detalhe.lote || "",
          conservacaoApoio: detalhe.conservacao || "",
          pedidoApoio: detalhe.pedido || "",
          pedidoAlfanumericoApoio: detalhe.pedidoAlfanumerico || "",
          quantidadeExamesNaLinhaApoio: detalhe.quantidadeExamesNaLinha ?? "",
          ultimoEventoBagApoio: detalhe.ultimoEventoBag || "",
          rowNumberOriginalApoio: detalhe.row_number_original || "",

          dadosWorklab: null,

          dadosApoio: montarDadosApoio(
            dadosApoioOriginal,
            detalhe
          )
        }
      });
    });

    continue;
  }

  // ======================================================
  // CASO 4: NÃO TEM NADA PARA EXPLODIR
  // ======================================================
  resultado.push({
    json: {
      ...item,
      origemExplodida: "",
      indiceRegistroWorklab: 0,
      totalRegistrosWorklab: 0,
      indiceDetalheApoio: 0,
      totalDetalhesApoio: 0
    }
  });
}

return resultado;
